const d = JSON.parse((($input.first().json.stdout)||'{}').toString().trim());
const TH = 15; // warn when fewer than 15 days left
const certs = d.certs || [];
const breached = certs.filter(c => Number(c.days) < TH).map(c => c.name);
const store = $getWorkflowStaticData('global');
const prev = store.vg_ssl || [];
const newly = breached.filter(n => !prev.includes(n));
const recovered = prev.filter(n => !breached.includes(n));
store.vg_ssl = breached;
if (newly.length === 0 && recovered.length === 0) return [];
const dayOf = n => { const c = certs.find(x => x.name === n); return c ? c.days : '?'; };
const lines = [];
if (newly.length) { lines.push('\uD83D\uDD36 *VertiGuard \u2014 SSL expiring soon*'); newly.forEach(n => lines.push('\u2022 ' + n + ': ' + dayOf(n) + ' days')); }
if (recovered.length) { if (lines.length) lines.push(''); lines.push('\uD83D\uDFE2 *VertiGuard \u2014 SSL renewed*'); recovered.forEach(n => lines.push('\u2022 ' + n + ': ' + dayOf(n) + ' days')); }
lines.push(''); lines.push('\uD83D\uDD52 ' + (d.ts || ''));
return [{ json: { message: lines.join('\n') } }];
